package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.text.InputType
import android.view.View
import android.widget.Button
import android.widget.EditText
import android.widget.ProgressBar
import android.widget.TextView
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import androidx.core.widget.doAfterTextChanged

object AuthPrefs {
    private const val PREFS_NAME = "auth_prefs"
    private const val KEY_AUTHENTICATED = "authenticated"

    fun prefs(context: Context): SharedPreferences =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    fun isAuthenticated(context: Context): Boolean =
        prefs(context).getBoolean(KEY_AUTHENTICATED, false)

    fun setAuthenticated(context: Context, value: Boolean) {
        prefs(context).edit().putBoolean(KEY_AUTHENTICATED, value).apply()
    }

    fun clear(context: Context) {
        prefs(context).edit().clear().apply()
    }
}

class LauncherActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (AuthPrefs.isAuthenticated(this)) {
            startActivity(Intent(this, HomeActivity::class.java))
        } else {
            startActivity(Intent(this, LoginActivity::class.java))
        }
        finish()
    }
}

class LoginActivity : AppCompatActivity() {

    private lateinit var statusText: TextView
    private lateinit var passwordInput: EditText
    private lateinit var loginButton: Button
    private lateinit var biometricButton: Button
    private lateinit var progress: ProgressBar

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    private val correctPassword = "password123"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        if (AuthPrefs.isAuthenticated(this)) {
            goHome()
            return
        }

        statusText = findViewById(R.id.statusText)
        passwordInput = findViewById(R.id.passwordInput)
        loginButton = findViewById(R.id.loginButton)
        biometricButton = findViewById(R.id.biometricButton)
        progress = findViewById(R.id.progress)

        passwordInput.inputType = InputType.TYPE_CLASS_TEXT or InputType.TYPE_TEXT_VARIATION_PASSWORD

        loginButton.isEnabled = false
        passwordInput.doAfterTextChanged {
            loginButton.isEnabled = !it.isNullOrBlank()
        }

        loginButton.setOnClickListener {
            attemptPasswordLogin()
        }

        setupBiometric()

        biometricButton.setOnClickListener {
            startBiometric()
        }

        val canUseBiometric = canUseBiometric()
        biometricButton.visibility = if (canUseBiometric) View.VISIBLE else View.GONE

        if (canUseBiometric) {
            statusText.text = getString(R.string.login_status_biometric_ready)
            startBiometric()
        } else {
            statusText.text = getString(R.string.login_status_password_only)
        }
    }

    private fun setupBiometric() {
        val executor = ContextCompat.getMainExecutor(this)
        biometricPrompt = BiometricPrompt(this, executor, object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                onAuthenticated()
            }

            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                statusText.text = errString
                showPasswordFallbackHint()
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                statusText.text = getString(R.string.login_status_biometric_failed_try_again_or_password)
                showPasswordFallbackHint()
            }
        })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle(getString(R.string.biometric_title))
            .setSubtitle(getString(R.string.biometric_subtitle))
            .setNegativeButtonText(getString(R.string.biometric_use_password))
            .build()
    }

    private fun canUseBiometric(): Boolean {
        val manager = BiometricManager.from(this)
        return manager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG) == BiometricManager.BIOMETRIC_SUCCESS
    }

    private fun startBiometric() {
        if (!canUseBiometric()) {
            statusText.text = getString(R.string.login_status_password_only)
            biometricButton.visibility = View.GONE
            return
        }
        statusText.text = getString(R.string.login_status_touch_sensor)
        biometricPrompt.authenticate(promptInfo)
    }

    private fun showPasswordFallbackHint() {
        biometricButton.visibility = if (canUseBiometric()) View.VISIBLE else View.GONE
        passwordInput.requestFocus()
    }

    private fun attemptPasswordLogin() {
        setLoading(true)
        val entered = passwordInput.text?.toString().orEmpty()

        passwordInput.postDelayed({
            if (entered == correctPassword) {
                onAuthenticated()
            } else {
                setLoading(false)
                statusText.text = getString(R.string.login_status_wrong_password)
                passwordInput.error = getString(R.string.login_error_wrong_password)
            }
        }, 350)
    }

    private fun onAuthenticated() {
        AuthPrefs.setAuthenticated(this, true)
        goHome()
    }

    private fun goHome() {
        startActivity(Intent(this, HomeActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        })
        finish()
    }

    private fun setLoading(loading: Boolean) {
        progress.visibility = if (loading) View.VISIBLE else View.GONE
        loginButton.isEnabled = !loading && !passwordInput.text.isNullOrBlank()
        biometricButton.isEnabled = !loading
        passwordInput.isEnabled = !loading
    }
}

class HomeActivity : AppCompatActivity() {

    private lateinit var welcomeText: TextView
    private lateinit var logoutButton: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home)

        welcomeText = findViewById(R.id.welcomeText)
        logoutButton = findViewById(R.id.logoutButton)

        welcomeText.text = getString(R.string.home_welcome)

        logoutButton.setOnClickListener {
            confirmLogout()
        }
    }

    private fun confirmLogout() {
        AlertDialog.Builder(this)
            .setTitle(getString(R.string.logout_title))
            .setMessage(getString(R.string.logout_message))
            .setPositiveButton(getString(R.string.logout_yes)) { _, _ ->
                AuthPrefs.clear(this)
                startActivity(Intent(this, LoginActivity::class.java).apply {
                    flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
                })
                finish()
            }
            .setNegativeButton(getString(R.string.logout_no), null)
            .show()
    }
}